import{_ as e,o as t,c as i,a2 as s}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"根据数据提出产品假设","description":"","frontmatter":{"title":"根据数据提出产品假设","stage":"intermediate","direction":"product","tags":["product","metrics","hypothesis","experimentation"]},"headers":[],"relativePath":"02-product/notes/06-metrics-experiments/08-data-to-hypothesis.md","filePath":"02-product/notes/06-metrics-experiments/08-data-to-hypothesis.md","lastUpdated":1784542968000}'),r={name:"02-product/notes/06-metrics-experiments/08-data-to-hypothesis.md"};function n(l,a,h,d,o,p){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="根据数据提出产品假设-从模式到可区分预测" tabindex="-1">根据数据提出产品假设：从模式到可区分预测 <a class="header-anchor" href="#根据数据提出产品假设-从模式到可区分预测" aria-label="Permalink to &quot;根据数据提出产品假设：从模式到可区分预测&quot;">​</a></h1><p>数据可以暴露模式和异常，但不会自动给出原因或方案。产品假设需要明确机制、目标主体、干预、预期结果、替代解释和能区分解释的证据。</p><h2 id="一、观察、解释、干预分开" tabindex="-1">一、观察、解释、干预分开 <a class="header-anchor" href="#一、观察、解释、干预分开" aria-label="Permalink to &quot;一、观察、解释、干预分开&quot;">​</a></h2><p>观察：移动搜索零结果率从 8% 升到 14%。解释候选：词库覆盖下降、事件重复、流量来源改变、拼写差异、索引延迟。干预候选：纠错、同义词、索引修复、来源引导。</p><p>直接从“零结果升高”跳到“做 AI 搜索”把解释和方案绑死。先验证口径与数据，再列可证伪解释。</p><h2 id="二、假设最小结构" tabindex="-1">二、假设最小结构 <a class="header-anchor" href="#二、假设最小结构" aria-label="Permalink to &quot;二、假设最小结构&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>对于 [目标主体/场景]，</span></span>
<span class="line"><span>如果 [可控制干预]，</span></span>
<span class="line"><span>那么 [主指标] 会在 [窗口] 内 [方向和最小实际变化]，</span></span>
<span class="line"><span>因为 [机制]；</span></span>
<span class="line"><span>同时 [护栏] 不越界。</span></span>
<span class="line"><span>如果看到 [区分证据]，则支持/反驳该机制。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>“提升转化”没有分母、基线、窗口和机制，不是可执行假设。</p><h2 id="三、先验证数据生成过程" tabindex="-1">三、先验证数据生成过程 <a class="header-anchor" href="#三、先验证数据生成过程" aria-label="Permalink to &quot;三、先验证数据生成过程&quot;">​</a></h2><p>检查事件 schema、版本、重复、缺失、identity、时区、成熟度、客户端/服务端差异和流量组成。数据异常可能是产品变化，也可能是测量变化。</p><p>建立异常时间线：指标何时改变、哪个事件/维度先变、是否与发布/营销/数据管线同刻、原始业务记录是否一致。</p><h2 id="四、提出互斥预测" tabindex="-1">四、提出互斥预测 <a class="header-anchor" href="#四、提出互斥预测" aria-label="Permalink to &quot;四、提出互斥预测&quot;">​</a></h2><p>多个解释若预测相同结果，现有数据无法区分。</p><table tabindex="0"><thead><tr><th>解释</th><th>可区分预测</th><th>验证</th></tr></thead><tbody><tr><td>索引延迟</td><td>新上架商品、发布后短窗口更严重</td><td>关联商品更新时间和索引时间</td></tr><tr><td>拼写问题</td><td>编辑距离近的查询占比升高</td><td>离线查询集与纠错模拟</td></tr><tr><td>流量变化</td><td>特定 campaign/地区权重改变</td><td>分群与标准化</td></tr><tr><td>埋点重复</td><td>同 requestId 多个 zero_result</td><td>去重与服务端日志对账</td></tr></tbody></table><h2 id="五、证据梯度" tabindex="-1">五、证据梯度 <a class="header-anchor" href="#五、证据梯度" aria-label="Permalink to &quot;五、证据梯度&quot;">​</a></h2><p>日志与描述分析适合发现；定性会话适合理解机制；原型/可用性测试验证交互可行；随机实验估计干预效果；灰度与长期观察验证外部有效性。</p><p>更强方法不一定可行。不可随机化时使用时间中断、差分中的差分或匹配需要额外假设，并明确未观测混杂。</p><h2 id="六、案例一-搜索零结果" tabindex="-1">六、案例一：搜索零结果 <a class="header-anchor" href="#六、案例一-搜索零结果" aria-label="Permalink to &quot;六、案例一：搜索零结果&quot;">​</a></h2><h3 id="观察" tabindex="-1">观察 <a class="header-anchor" href="#观察" aria-label="Permalink to &quot;观察&quot;">​</a></h3><p>移动端零结果率 8%→14%，桌面保持 7%。零结果按服务端 requestId 去重；客户端 query_submitted 数量正常。</p><h3 id="分解" tabindex="-1">分解 <a class="header-anchor" href="#分解" aria-label="Permalink to &quot;分解&quot;">​</a></h3><p>Android 9.4 上升到 21%，其他版本 8%；该版本输入法处理把 <code>+</code> 解码为空格，SKU <code>A+B</code> 变成 <code>A B</code>。服务端原始查询日志确认。</p><h3 id="假设" tabindex="-1">假设 <a class="header-anchor" href="#假设" aria-label="Permalink to &quot;假设&quot;">​</a></h3><p>对 Android 9.4 的 SKU 查询，如果修复加号编码，那么该版本精确 SKU 零结果率 7 日内至少下降 10 个百分点，因为服务端将收到正确字面值；搜索 p95 和崩溃率不恶化。</p><h3 id="设计" tabindex="-1">设计 <a class="header-anchor" href="#设计" aria-label="Permalink to &quot;设计&quot;">​</a></h3><p>随机 bucket 对一半合格 9.4 会话启用编码修复。单位是设备安装，避免同人会话交叉。主要指标是精确 SKU 零结果率；次要是成功商品打开；护栏是请求错误和延迟。</p><h3 id="数据" tabindex="-1">数据 <a class="header-anchor" href="#数据" aria-label="Permalink to &quot;数据&quot;">​</a></h3><p>control 10,000 查询中 2,100 零结果；treatment 10,200 中 918。分别 21% 与 9%，绝对 -12 点。还需区间、SRM、暴露正确性和至少完整业务周期。</p><h3 id="反证" tabindex="-1">反证 <a class="header-anchor" href="#反证" aria-label="Permalink to &quot;反证&quot;">​</a></h3><p>若服务端 raw query 已相同而结果仍差，编码机制被反驳，应检查版本与索引路由。不能只因总体改善就保留错误解释。</p><h3 id="推广" tabindex="-1">推广 <a class="header-anchor" href="#推广" aria-label="Permalink to &quot;推广&quot;">​</a></h3><p>修复 rollout 后按版本监控；旧 9.4 仍存在，服务端是否兼容需另行决定。实验只覆盖精确 SKU，不外推自然语言相关性。</p><h2 id="七、案例二-试用流失" tabindex="-1">七、案例二：试用流失 <a class="header-anchor" href="#七、案例二-试用流失" aria-label="Permalink to &quot;七、案例二：试用流失&quot;">​</a></h2><h3 id="观察-1" tabindex="-1">观察 <a class="header-anchor" href="#观察-1" aria-label="Permalink to &quot;观察&quot;">​</a></h3><p>14 日试用转付费从 18% 降到 14%。下降集中在小团队 paid-search 来源，首日创建项目率正常，邀请第二成员率下降。</p><h3 id="解释候选" tabindex="-1">解释候选 <a class="header-anchor" href="#解释候选" aria-label="Permalink to &quot;解释候选&quot;">​</a></h3><p>A：新手流程弱化邀请入口；B：广告引入更小/单人团队；C：邀请邮件投递下降；D：cohort 未成熟或归因规则变化。</p><h3 id="检验" tabindex="-1">检验 <a class="header-anchor" href="#检验" aria-label="Permalink to &quot;检验&quot;">​</a></h3><p>归因规则未变，cohort 已成熟。邮件 delivery 与 click 正常。新手版本发布后入口曝光从 70% 降到 30%，但 paid-search 同时带来更多单人团队。</p><h3 id="两个假设" tabindex="-1">两个假设 <a class="header-anchor" href="#两个假设" aria-label="Permalink to &quot;两个假设&quot;">​</a></h3><p>H1：恢复邀请入口对有第二成员意图的工作区提高邀请完成和付费。H2：对真实单人工作区强调个人价值比邀请更有效。一个统一邀请干预可能伤害 H2 人群。</p><h3 id="分层实验" tabindex="-1">分层实验 <a class="header-anchor" href="#分层实验" aria-label="Permalink to &quot;分层实验&quot;">​</a></h3><p>在开户问卷/行为推断的团队意图层随机化不同引导。主要结果是成熟的 14 日付费；领先是邀请完成或个人核心任务；护栏是跳出、退订和支持。</p><p>意图分类可能受处理影响时必须在 assignment 前固定。用实验后行为定义群会产生选择偏差。</p><h2 id="八、从-sql-到假设卡" tabindex="-1">八、从 SQL 到假设卡 <a class="header-anchor" href="#八、从-sql-到假设卡" aria-label="Permalink to &quot;八、从 SQL 到假设卡&quot;">​</a></h2><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> source, onboarding_version,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">       COUNT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mature_trials,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">       AVG</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(converted_14d::</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> conversion_14d,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">       AVG</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(invited_member_2d::</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> invite_2d</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> trial_cohort_facts</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mature_14d</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GROUP BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> source, onboarding_version;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>输出保留分子、分母和版本。分析 notebook 记录查询 commit、数据 as-of 和排除。假设卡引用结果，不复制一个不可复现百分比。</p><h2 id="九、优先级" tabindex="-1">九、优先级 <a class="header-anchor" href="#九、优先级" aria-label="Permalink to &quot;九、优先级&quot;">​</a></h2><p>按影响单位、差距、证据强度、可逆性、成本与风险排序。<code>影响人数×可能变化</code> 是粗估，不应伪装精确。</p><p>高影响但证据弱可先做低成本测量或原型；高风险不可逆先验证机制和安全。</p><h2 id="十、预注册与停止规则" tabindex="-1">十、预注册与停止规则 <a class="header-anchor" href="#十、预注册与停止规则" aria-label="Permalink to &quot;十、预注册与停止规则&quot;">​</a></h2><p>实验前写主要指标、单位、样本、最小可检测效应、窗口、排除、分群、护栏和停止规则。看到结果后换指标增加假阳性。</p><p>数据质量失败如 SRM、暴露日志缺失、跨组污染会使结果不可解释，不等于“实验无效果”。</p><h2 id="十一、失败与负结果" tabindex="-1">十一、失败与负结果 <a class="header-anchor" href="#十一、失败与负结果" aria-label="Permalink to &quot;十一、失败与负结果&quot;">​</a></h2><p>无显著差异不证明完全相等。报告估计与区间：可排除多大改善、样本是否足够。</p><p>机制指标变化但结果未变，可能窗口不足、过程不是因果、剂量不足或护栏抵消。保留学习，避免重复假设。</p><h2 id="十二、假设注册表" tabindex="-1">十二、假设注册表 <a class="header-anchor" href="#十二、假设注册表" aria-label="Permalink to &quot;十二、假设注册表&quot;">​</a></h2><p>字段包括 hypothesis_id、observation、mechanism、intervention、population、unit、primary metric、MDE、window、guardrails、alternatives、status、decision 和 evidence links。</p><p>状态 proposed→measuring→testing→supported/not_supported/inconclusive→retired。supported 只针对已测试范围，不变成永恒事实。</p><h2 id="十三、样本与效应" tabindex="-1">十三、样本与效应 <a class="header-anchor" href="#十三、样本与效应" aria-label="Permalink to &quot;十三、样本与效应&quot;">​</a></h2><p>样本规划使用基线率、最小实际效应、显著性、power、分配比例和设计效应。不能用“跑两周”替代。cluster随机按组内相关调整；同一单位重复事件不是新增样本。</p><p>流量不足时接受更宽区间、选择更近的机制指标或扩大可控范围，不能看到趋势就提前宣布。</p><h2 id="十四、决策规则" tabindex="-1">十四、决策规则 <a class="header-anchor" href="#十四、决策规则" aria-label="Permalink to &quot;十四、决策规则&quot;">​</a></h2><p>发布要求主要效果区间达到实际阈值、护栏不越界、SRM/质量通过、关键预注册群无不可接受伤害。</p><p>inconclusive 可以停止、扩大、改测量或放弃；不把方向正确当成功。</p><h2 id="十五、定性与定量" tabindex="-1">十五、定性与定量 <a class="header-anchor" href="#十五、定性与定量" aria-label="Permalink to &quot;十五、定性与定量&quot;">​</a></h2><p>定量定位哪个群和步骤，定性理解行为与语言。观察不能估计代表性比例，但能发现机制与反例；新机制仍在新数据或实验验证。</p><h2 id="十六、顺序查看" tabindex="-1">十六、顺序查看 <a class="header-anchor" href="#十六、顺序查看" aria-label="Permalink to &quot;十六、顺序查看&quot;">​</a></h2><p>频繁查看固定样本p值并显著就停会提高假阳性。采用固定horizon或经设计的sequential方法；规则在实验前进入注册表。</p><h2 id="十七、常见错误" tabindex="-1">十七、常见错误 <a class="header-anchor" href="#十七、常见错误" aria-label="Permalink to &quot;十七、常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th>错误</th><th>修正</th></tr></thead><tbody><tr><td>图表异常直接变方案</td><td>列解释和预测</td></tr><tr><td>只找支持证据</td><td>设计反证</td></tr><tr><td>结果后定义分群</td><td>assignment 前固定</td></tr><tr><td>相关当因果</td><td>实验/因果假设</td></tr><tr><td>无效果=没价值</td><td>报区间和可排除范围</td></tr><tr><td>数据 bug 当产品问题</td><td>先审计生成过程</td></tr></tbody></table><h2 id="十八、综合练习" tabindex="-1">十八、综合练习 <a class="header-anchor" href="#十八、综合练习" aria-label="Permalink to &quot;十八、综合练习&quot;">​</a></h2><p>从一个真实漏斗下降提出至少三个可区分解释和两个干预假设。</p><h3 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h3><ul><li>[ ] 观察、解释和方案分开。</li><li>[ ] 每个解释有不同预测和反证。</li><li>[ ] SQL 可复现且含分母/版本。</li><li>[ ] 假设写干预、机制、窗口和最小变化。</li><li>[ ] 实验单位、护栏、SRM 与停止规则明确。</li><li>[ ] 负结果用区间解释。</li></ul><h2 id="十九、搜索假设的离线评估" tabindex="-1">十九、搜索假设的离线评估 <a class="header-anchor" href="#十九、搜索假设的离线评估" aria-label="Permalink to &quot;十九、搜索假设的离线评估&quot;">​</a></h2><p>在在线实验前建立标注查询集：高频、长尾、SKU、拼写、同义词、无可用商品和安全敏感查询。标注正确商品/允许空结果，按 query type 报 Precision@k、Recall@k、NDCG@k 和零结果。</p><p>离线相关性提升不保证用户任务成功。它用于淘汰明显错误方案、发现群体伤害和控制实验风险。标注者一致性与数据时间范围进入报告。</p><h2 id="二十、机制链的逐点测量" tabindex="-1">二十、机制链的逐点测量 <a class="header-anchor" href="#二十、机制链的逐点测量" aria-label="Permalink to &quot;二十、机制链的逐点测量&quot;">​</a></h2><p>邀请引导假设的链路：</p><p><code>入口曝光 → 理解价值 → 发出邀请 → 成员接受 → 共同完成任务 → 付费</code>。</p><p>每个节点有事件和资格。若曝光提升但邀请不变，检查理解/交互；邀请提升但接受不变，检查邮件与对象；共同任务提升而付费不变，机制与商业结果可能断开。</p><p>不要因为最终指标未成熟就选择最有利中间节点。预先指定哪一个过程是机制验证、何时等待最终结果。</p><h2 id="二十一、实验失败矩阵" tabindex="-1">二十一、实验失败矩阵 <a class="header-anchor" href="#二十一、实验失败矩阵" aria-label="Permalink to &quot;二十一、实验失败矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>故障</th><th>结论状态</th><th>处理</th></tr></thead><tbody><tr><td>SRM</td><td>invalid</td><td>修分配/日志后重跑</td></tr><tr><td>exposure 大量缺失</td><td>invalid 或边界缩小</td><td>对账 assignment</td></tr><tr><td>主要指标 schema 变更</td><td>不可直接拼接</td><td>并行口径</td></tr><tr><td>护栏严重越界</td><td>停止</td><td>回滚并调查</td></tr><tr><td>样本不足</td><td>inconclusive</td><td>报区间/重新规划</td></tr><tr><td>效果异质且预注册</td><td>按群决策</td><td>检查交互和公平</td></tr></tbody></table><h2 id="二十二、假设组合与冲突" tabindex="-1">二十二、假设组合与冲突 <a class="header-anchor" href="#二十二、假设组合与冲突" aria-label="Permalink to &quot;二十二、假设组合与冲突&quot;">​</a></h2><p>同一漏斗可能有多个同时实验，互相影响。建立互斥层或正交分桶，记录其他实验 exposure。关键交互需要 factorial 设计或避免重叠。</p><p>产品假设与测量假设分开：“新入口提高邀请”与“invite_sent 事件完整”不是同一假设。后者先通过数据质量验证。</p><h2 id="二十三、学习复用" tabindex="-1">二十三、学习复用 <a class="header-anchor" href="#二十三、学习复用" aria-label="Permalink to &quot;二十三、学习复用&quot;">​</a></h2><p>not_supported 记录同样重要：保留人群、版本、剂量、区间和失败机制。下一次假设必须说明新增证据，避免换文案重复测试。</p><p>结果随产品/市场漂移，旧实验不是永久真理。外推到新地区、设备或价格前检查机制和边界。</p><h2 id="二十四、最小可检测效应与实际阈值" tabindex="-1">二十四、最小可检测效应与实际阈值 <a class="header-anchor" href="#二十四、最小可检测效应与实际阈值" aria-label="Permalink to &quot;二十四、最小可检测效应与实际阈值&quot;">​</a></h2><p>MDE 是实验按给定样本计划能可靠检测的效应，不等于业务最小价值。先由产品定义最小有意义效应，再检查流量能否达到相应精度；不能反过来把平台默认MDE称为商业阈值。</p><p>若14日付费基线14%，业务要求至少+1.5点，样本规划使用绝对差、双侧/单侧选择、power和流失。最终报告区间是否排除0及是否达到1.5点。</p><h2 id="二十五、实验单位与曝光" tabindex="-1">二十五、实验单位与曝光 <a class="header-anchor" href="#二十五、实验单位与曝光" aria-label="Permalink to &quot;二十五、实验单位与曝光&quot;">​</a></h2><p>assignment 在工作区，结果也按工作区；成员事件先聚合。若按成员随机但共享同一工作区，界面和行为交叉污染。</p><p>exposure 是实际看到处理，不应替代 assignment 做主ITT。exposure缺失用于质量诊断；按曝光者分析会选择受处理影响的人。</p><h2 id="二十六、停止与回滚" tabindex="-1">二十六、停止与回滚 <a class="header-anchor" href="#二十六、停止与回滚" aria-label="Permalink to &quot;二十六、停止与回滚&quot;">​</a></h2><p>严重安全、数据丢失或费用失控立即停止，不等待统计显著。常规护栏按预设区间/阈值和最小样本判断，避免噪声频繁回滚。</p><p>回滚后继续收集已分配单位的成熟结果，识别延迟伤害。停止新 exposure 不等于删除实验历史。</p><h2 id="二十七、假设评审实例" tabindex="-1">二十七、假设评审实例 <a class="header-anchor" href="#二十七、假设评审实例" aria-label="Permalink to &quot;二十七、假设评审实例&quot;">​</a></h2><p>评审者分别提出最强反例、最可能测量错误、可能被处理影响的分群和不可接受护栏。无法写反证的假设通常过于模糊。</p><p>把决策阈值写成表：支持、反对、inconclusive、invalid 各对应行动。团队在看结果前同意规则。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.itl.nist.gov/div898/handbook/eda/section3/eda352.htm" target="_blank" rel="noreferrer">NIST：Confidence Limits for the Mean</a>（访问日期：2026-07-18）</li><li><a href="https://arxiv.org/abs/2208.07766" target="_blank" rel="noreferrer">eBay：Randomization Validation and SRM Detection</a>（访问日期：2026-07-18）</li><li><a href="https://research.google.com/pubs/archive/36500.pdf" target="_blank" rel="noreferrer">Google：Overlapping Experiment Infrastructure</a>（访问日期：2026-07-18）</li><li><a href="https://escholarship.org/uc/item/6gv9n38c" target="_blank" rel="noreferrer">Causal Diagrams for Empirical Research</a>（访问日期：2026-07-18）</li></ul>`,105)])])}const b=e(r,[["render",n]]);export{u as __pageData,b as default};
